server {
    server_name api.ahnj.info _;
    client_max_body_size 100M;
    location / {
        proxy_pass http://127.0.0.1:8000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_read_timeout 300s;
        proxy_buffering off;
    }

    listen 443 ssl; # managed by Certbot
    ssl_certificate /etc/letsencrypt/live/api.ahnj.info/fullchain.pem; # managed by Certbot
    ssl_certificate_key /etc/letsencrypt/live/api.ahnj.info/privkey.pem; # managed by Certbot
    include /etc/letsencrypt/options-ssl-nginx.conf; # managed by Certbot
    ssl_dhparam /etc/letsencrypt/ssl-dhparams.pem; # managed by Certbot

}
server {
    if ($host = api.ahnj.info) {
        return 301 https://$host$request_uri;
    } # managed by Certbot


    listen 80;
    server_name api.ahnj.info _;
    return 404; # managed by Certbot


